public static <T> T createValue(final String str, final Class<T> clazz) throws ParseException {
    if (str == null) {
        return null;
    }
    if (clazz.isAssignableFrom(String.class)) {
        return (T) str;
    } else if (clazz.isAssignableFrom(Object.class)) {
        return (T) createObject(str);
    } else if (clazz.isAssignableFrom(Number.class)) {
        return (T) createNumber(str);
    } else if (clazz.isAssignableFrom(Date.class)) {
        return (T) createDate(str);
    } else if (clazz.isAssignableFrom(Class.class)) {
        return (T) createClass(str);
    } else if (clazz.isAssignableFrom(File.class)) {
        return (T) createFile(str);
    } else if (clazz.isAssignableFrom(URL.class)) {
        return (T) createURL(str);
    } else {
        throw new ParseException("Unknown type: " + clazz);
    }
}
